def get_or_set(key)
  @mutex.synchronize do
    return @store[key][:value] if @store.key?(key) && !expired?(@store[key])

    value = fetch_from_source(key)
    @store[key] = {
      value: value,
      expires_at: Time.now + @ttl,
      created_at: Time.now
    }
    touch(key)
    value
  end
end

# Use a Hash as an ordered set (Ruby 1.9+ maintains insertion order)
# Replace @access_order Array with @access_order Hash in initialize
def touch(key)
  @access_order.delete(key)
  @access_order[key] = true
end

